                background: var(--bg-section-light);
                color: var(--dark-primary);
                padding: 8px 15px;
                border-radius: 20px;
                font-size: 14px;
                font-weight: 600;
              }
            }
          }
        }

        .btn {
          margin-bottom: 15px;
        }

        .quote-note {
          font-size: 13px;
          color: rgba(26, 29, 35, 0.7);
          margin: 0;
        }
      }
    }

    /* CTA SECTION */
    .cta-section {
      background: var(--dark-primary);
      text-align: center;
      padding: 80px 0;

      h2 {
        color: var(--text-light);
        font-size: clamp(2rem, 4vw, 3rem);
        margin-bottom: 20px;
      }

      p {
        color: rgba(255, 255, 255, 0.8);
        font-size: 1.2rem;
        margin-bottom: 30px;
      }
    }

    /* RESPONSIVE */
    @media (max-width: 1024px) {
      .vehicle-display {
        grid-template-columns: 1fr;
      }

      .vehicle-360 {
        border-right: none;
        border-bottom: 2px solid var(--bg-section-light);
