      .rotation-controls {
        .rotation-btn {
          width: 40px;
          height: 40px;
          font-size: 20px;
        }
      }

      .vehicle-view-large {
        max-width: 400px;
        height: 300px;
      }
    }

    @media (max-width: 480px) {
      .vehicle-types-grid {
        grid-template-columns: 1fr;
      }

      .vehicle-view-large {
        max-width: 320px;
        height: 240px;
      }
    }
